(function(){
function $(id){return document.getElementById(id);}
function openModal(id){var el=$(id); if(el){el.classList.add('open');}}
function closeModal(id){var el=$(id); if(el){el.classList.remove('open');}}
var data = window.LESSON_DATA || {};
var PAGE_LANG = data.htmlLang || document.documentElement.lang || 'ar';
var AUDIO_LANG = data.audioLang || 'ar-SA';
var LESSON_TEXT = data.lessonText || '';
var AI_PROMPTS = data.aiPrompts || {};
var UI = data.ui || {};
var audioPlaying = false;
function goLesson(){
var input = $('jumpInput');
var n = parseInt(input && input.value,10);
if(!n || n < 1 || n > 150){return;}
window.location.href = 'L' + String(n).padStart(3,'0') + '.html';
}
function getBestVoice(){
var voices = window.speechSynthesis ? speechSynthesis.getVoices() : [];
return voices.find(function(v){return (v.lang || '').toLowerCase().indexOf(AUDIO_LANG.toLowerCase()) === 0;})
|| voices.find(function(v){return (v.lang || '').toLowerCase().indexOf(PAGE_LANG.toLowerCase()) === 0;})
|| false;
}
function toggleAudio(){
var btn = $('audioBtn');
if(!window.speechSynthesis){alert(UI.audioUnavailable || 'الصوت غير متوفر على هذا الجهاز.'); return;}
if(audioPlaying){
speechSynthesis.cancel(); audioPlaying = false;
if(btn){btn.textContent = UI.listen || 'استمع 🔊';}
var nav = $('bottomNav'); if(nav){nav.style.display = 'grid';}
return;
}
var utter = new SpeechSynthesisUtterance(LESSON_TEXT);
var voice = getBestVoice();
utter.lang = AUDIO_LANG;
if(voice){utter.voice = voice;}
utter.rate = 0.88; utter.pitch = 1;
utter.onend = function(){audioPlaying = false; if(btn){btn.textContent = UI.listen || 'استمع 🔊';} var nav=$('bottomNav'); if(nav){nav.style.display='grid';}};
utter.onerror = function(){audioPlaying = false; if(btn){btn.textContent = UI.listen || 'استمع 🔊';} var nav=$('bottomNav'); if(nav){nav.style.display='grid';} alert(UI.audioUnavailable || 'الصوت غير متوفر على هذا الجهاز.');};
audioPlaying = true;
if(btn){btn.textContent = UI.stop || 'إيقاف ■';}
var nav = $('bottomNav'); if(nav){nav.style.display = 'none';}
speechSynthesis.cancel();
speechSynthesis.speak(utter);
}
function aiHelp(mode){
var prompt = AI_PROMPTS[mode] || AI_PROMPTS.explain || '';
var out = $('aiOutput');
if(out){out.textContent = prompt + "\n\n" + LESSON_TEXT.slice(0,900);}
}
function shareWhatsApp(){
window.open("https://wa.me/?text=" + encodeURIComponent(document.title + " " + window.location.href), "_blank");
}
document.addEventListener('DOMContentLoaded', function(){
var audioBtn=$('audioBtn'), aiOpenBtn=$('aiOpenBtn'), quickOpenBtn=$('quickOpenBtn'), shareBtn=$('shareBtn'), quickGoBtn=$('quickGoBtn');
if(audioBtn){audioBtn.addEventListener('click', toggleAudio);}
if(aiOpenBtn){aiOpenBtn.addEventListener('click', function(){openModal('aiModal');});}
if(quickOpenBtn){quickOpenBtn.addEventListener('click', function(){openModal('quickModal');});}
if(shareBtn){shareBtn.addEventListener('click', shareWhatsApp);}
if(quickGoBtn){quickGoBtn.addEventListener('click', goLesson);}
document.querySelectorAll('[data-close]').forEach(function(btn){btn.addEventListener('click', function(){closeModal(btn.getAttribute('data-close'));});});
document.querySelectorAll('[data-ai-mode]').forEach(function(btn){btn.addEventListener('click', function(){aiHelp(btn.getAttribute('data-ai-mode'));});});
});
if(window.speechSynthesis){speechSynthesis.onvoiceschanged = function(){speechSynthesis.getVoices();};}
})();